export function fireRowToggleEvent(dt, rowKeyValue, expanded) {
    dt.dispatchEvent(new CustomEvent('privatetogglecell', {
        bubbles: true,
        composed: true,
        cancelable: true,
        detail: {
            name: rowKeyValue,
            nextState: expanded ? false : true,
        },
    }));
}
